mapper.select:
SELECT id, user_id, category, term, meaning, example, example_translation, pronunciation, difficulty_level, mastery, next_review_date, tags::text, created_at, ease_factor, interval_days, repetitions, lapses
FROM vocab_cards
WHERE id = #{id}
  AND user_id = #{userId}

mapper.update:
UPDATE vocab_cards
SET category = #{category},
    term = #{term},
    meaning = #{meaning},
    example = #{example},
    pronunciation = #{pronunciation}
WHERE id = #{id}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM vocab_cards
WHERE id = #{id}
  AND user_id = #{userId}

mapper.update:
UPDATE vocab_cards
SET mastery = #{mastery},
    next_review_date = CAST(#{nextReviewDate} AS date),
    last_reviewed_at = NOW()
WHERE id = #{id}
  AND user_id = #{userId}
